import java.util.*;
public class EmployeeDepartmentSalaryComparator { static class Employee { String name, department; double salary; Employee(String name, String department, double salary) { this.name = name; this.department = department; this.salary = salary; } public String toString() { return name + " " + department + " " + salary; } } public static void main(String[] args) { List<Employee> employees = new ArrayList<>(); employees.add(new Employee("Arun", "IT", 60000)); employees.add(new Employee("Bala", "HR", 50000)); employees.add(new Employee("Chitra", "IT", 55000)); employees.sort(Comparator.comparing((Employee e) -> e.department).thenComparing(Comparator.comparingDouble((Employee e) -> e.salary).reversed())); System.out.println(employees); } }
